const item = $input.first();

// Guard: check for Open-Meteo application-level errors (HTTP 200 with error:true)
if (item.json.error === true) {
  throw new Error('Open-Meteo API error: ' + (item.json.reason || 'unknown reason') + ' | Full response: ' + JSON.stringify(item.json));
}

// Guard: validate API response shape
if (!item.json.current_weather) {
  throw new Error('API response missing current_weather: ' + JSON.stringify(item.json));
}

const cw = item.json.current_weather;
const temp = cw.temperature;
const windspeed = cw.windspeed;
const code = cw.weathercode;
const time = cw.time;

// Guard: validate all required current_weather fields are present and non-null
if (temp == null || windspeed == null || code == null || !time) {
  throw new Error('Incomplete current_weather fields: ' + JSON.stringify(cw));
}

// Guard: validate time format to catch unexpected API format changes
if (!/^\d{4}-\d{2}-\d{2}T/.test(time)) {
  throw new Error('Unexpected time format from API: ' + time);
}

// Extract daily fields safely (first element of each array)
const daily = item.json.daily || {};
const tempMax = (daily.temperature_2m_max && daily.temperature_2m_max[0] != null) ? daily.temperature_2m_max[0] : null;
const tempMin = (daily.temperature_2m_min && daily.temperature_2m_min[0] != null) ? daily.temperature_2m_min[0] : null;
const precipSum = (daily.precipitation_sum && daily.precipitation_sum[0] != null) ? daily.precipitation_sum[0] : null;

const wmoMap = {
  0: 'Clear sky',
  1: 'Mainly clear', 2: 'Partly cloudy', 3: 'Overcast',
  45: 'Fog', 48: 'Depositing rime fog',
  51: 'Light drizzle', 53: 'Moderate drizzle', 55: 'Dense drizzle',
  61: 'Slight rain', 63: 'Moderate rain', 65: 'Heavy rain',
  71: 'Slight snow', 73: 'Moderate snow', 75: 'Heavy snow',
  77: 'Snow grains',
  80: 'Slight rain showers', 81: 'Moderate rain showers', 82: 'Violent rain showers',
  85: 'Slight snow showers', 86: 'Heavy snow showers',
  95: 'Thunderstorm', 96: 'Thunderstorm with slight hail', 99: 'Thunderstorm with heavy hail'
};

const condition = wmoMap[code] || `Unknown (code ${code})`;
const isFreezing = temp <= 32;

// Safely extract date string by slicing the naive datetime string directly
// to avoid UTC misinterpretation by new Date() on a no-offset string
const datePart = time.substring(0, 10); // e.g. "2024-03-15"
const [year, month, day] = datePart.split('-').map(Number);
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
// Use noon UTC of the extracted date to avoid any day-boundary rollover
const dateObj = new Date(Date.UTC(year, month - 1, day, 12, 0, 0));
const weekday = dayNames[dateObj.getUTCDay()];
const dateStr = `${weekday}, ${monthNames[month - 1]} ${day}, ${year}`;

// Build daily summary lines if available
const dailyLines = [];
if (tempMax !== null) dailyLines.push(`📈  Today's High: ${tempMax}°F`);
if (tempMin !== null) dailyLines.push(`📉  Today's Low: ${tempMin}°F`);
if (precipSum !== null) dailyLines.push(`🌧️  Precipitation: ${precipSum} mm`);
const dailySummary = dailyLines.length > 0 ? '\n' + dailyLines.join('\n') : '';

// Build subject, body, alertLevel based on freezing flag
let subject, body, alertLevel;

if (isFreezing) {
  alertLevel = 'FREEZING';
  subject = `🚨 FREEZING ALERT: NYC Weather for ${dateStr}`;
  body = `🚨🚨🚨 FREEZING TEMPERATURE ALERT 🚨🚨🚨\n\nDate: ${dateStr}\n\n❄️  TEMPERATURE: ${temp}°F — BELOW OR AT FREEZING!\n💨  Wind Speed: ${windspeed} mph\n🌥️  Conditions: ${condition}${dailySummary}\n\n⚠️  WARNING: Temperatures are at or below 32°F. Dress in layers, protect pipes, and exercise caution on icy surfaces.\n\nStay warm and safe!`;
} else {
  alertLevel = 'NORMAL';
  subject = `🌤️ NYC Morning Weather for ${dateStr}`;
  body = `Good morning! Here's your NYC weather summary for ${dateStr}:\n\n🌡️  Temperature: ${temp}°F\n💨  Wind Speed: ${windspeed} mph\n🌥️  Conditions: ${condition}${dailySummary}\n\nHave a great day!`;
}

return [{
  json: {
    temperature: temp,
    windspeed: windspeed,
    weathercode: code,
    condition: condition,
    isFreezing: isFreezing,
    dateStr: dateStr,
    time: time,
    tempMax: tempMax,
    tempMin: tempMin,
    precipSum: precipSum,
    subject: subject,
    body: body,
    alertLevel: alertLevel
  }
}];

const webhookUrl = $env.WEATHER_WEBHOOK_URL;

if (!webhookUrl || webhookUrl.trim() === '') {
  throw new Error('Configuration error: WEATHER_WEBHOOK_URL environment variable is not set or is empty. Please configure this variable before running the workflow.');
}

if (!/^https?:\/\/.+/.test(webhookUrl.trim())) {
  throw new Error('Configuration error: WEATHER_WEBHOOK_URL does not appear to be a valid URL: ' + webhookUrl);
}

// Pass through all input data unchanged
return $input.all();
